@namespace sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Pages.Chat

<div class="channel-list">
    <div class="channel-list-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-items">
        @foreach (var channel in Channels)
        {
            var isActive = channel.Id == SelectedChannelId;
            <button class="channel-item @(isActive ? "active" : "")"
                    @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-name-row">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                @if (!string.IsNullOrWhiteSpace(channel.Description))
                {
                    <span class="channel-desc">@Truncate(channel.Description, 50)</span>
                }
            </button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Models.Channel> Channels { get; set; } = [];
    [Parameter] public int? SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

.channel-list {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #2c2f33;
    color: #dcddde;
}

.channel-list-header {
    padding: 16px;
    border-bottom: 1px solid #23262a;
}

.channel-list-header h3 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-items {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-item {
    display: block;
    width: 100%;
    text-align: left;
    background: none;
    border: none;
    color: #8e9297;
    padding: 6px 16px;
    cursor: pointer;
    transition: background 0.15s, color 0.15s;
    font-family: inherit;
}

.channel-item:hover {
    background: #34373c;
    color: #dcddde;
}

.channel-item.active {
    background: #393c42;
    color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
}

.channel-name {
    font-size: 15px;
    font-weight: 500;
}

.channel-item.active .channel-name,
.channel-item:hover .channel-name {
    font-weight: 600;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 11px;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 9px;
    min-width: 18px;
    text-align: center;
}

.channel-desc {
    font-size: 12px;
    color: #72767d;
    display: block;
    margin-top: 1px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

@namespace sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Pages.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <div class="no-replies">No replies yet. Start the conversation!</div>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <MessageBubble Message="reply" />
                }
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Models.Message? RootMessage { get; set; }
    [Parameter] public List<Models.Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    color: #666;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-quote {
    margin: 12px 16px;
    padding: 10px 12px;
    background: #f7f8fa;
    border-left: 3px solid #4a76a8;
    border-radius: 0 6px 6px 0;
}

.root-author {
    font-weight: 700;
    font-size: 14px;
    margin-bottom: 2px;
}

.root-content {
    font-size: 14px;
    color: #555;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.no-replies {
    text-align: center;
    color: #999;
    font-size: 14px;
    padding: 24px 16px;
}

