@namespace sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Pages.Chat

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <div class="no-replies">No replies yet. Start the conversation!</div>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <MessageBubble Message="reply" />
                }
            }
        </div>

        <MessageInput Placeholder="Reply in thread..."
                      ButtonText="Reply"
                      OnSubmit="OnReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Models.Message? RootMessage { get; set; }
    [Parameter] public List<Models.Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

.thread-header h4 {
    margin: 0;
    font-size: 16px;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 18px;
    color: #666;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-quote {
    margin: 12px 16px;
    padding: 10px 12px;
    background: #f7f8fa;
    border-left: 3px solid #4a76a8;
    border-radius: 0 6px 6px 0;
}

.root-author {
    font-weight: 700;
    font-size: 14px;
    margin-bottom: 2px;
}

.root-content {
    font-size: 14px;
