arguments.file_text:
@page "/chat"
@layout sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Layout.ChatLayout
@namespace sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Pages.Chat
@rendermode InteractiveServer
@inject Services.IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <!-- Left sidebar: Channel list -->
    <div class="panel-sidebar">
        <ChannelList Channels="_channels"
                     SelectedChannelId="_selectedChannelId"
                     OnChannelSelected="SelectChannelAsync" />
    </div>

    <!-- Main message area -->
    <div class="panel-main @(_threadRootMessage is null ? "panel-main--full" : "")">
        @if (_selectedChannel is not null)
        {
            <div class="main-header">
                <h2># @_selectedChannel.Name</h2>
                <span class="main-header-desc">@_selectedChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                                   OnOpenThread="OpenThreadAsync"
                                   OnReact="HandleReactionAsync" />
                }
                @if (_messages.Count == 0 && !_loading)
                {
                    <div class="empty-state">No messages yet. Start the conversation!</div>
                }
            </div>

            <MessageInput Placeholder="@($"Message #{_selectedChannel.Name}")"
                          ButtonText="Send"
                          OnSubmit="SendMessageAsync" />
        }
        else if (_loading)
        {
            <div class="loading-state">Loading…</div>
        }
    </div>

    <!-- Right panel: Thread view -->
    @if (_threadRootMessage is not null)
    {
        <div class="panel-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Models.Channel> _channels = [];
    private List<Models.Message> _messages = [];
    private List<Models.Message> _threadReplies = [];
    private Dictionary<int, int> _threadReplyCounts = new();

    private Models.Channel? _selectedChannel;
    private int? _selectedChannelId;
    private Models.Message? _threadRootMessage;

    private bool _loading;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0].Id);
        }

        _loading = false;
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (_selectedChannelId == channelId) return;

        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadReplyCounts = new();
        _threadRootMessage = null;
        _threadReplies = [];
        _allOlderLoaded = false;

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnreadCount(channelId);
    }

    private async Task SendMessageAsync(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we provide a manual trigger via the loading state.
        // The @onscroll fires on every scroll; we check position in a real app.
        // For this implementation, we load older messages when near the top.
        if (_loadingOlder || _allOlderLoaded || _selectedChannelId is null) return;

        // In a production app, you'd check scrollTop via JS interop.
        // Simplified: this method is called on scroll, we load if we haven't yet loaded all.
        await LoadOlderMessagesAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _selectedChannelId is null) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);

        if (older.Count < PageSize)
        {
            _allOlderLoaded = true;
        }

        _messages.InsertRange(0, older);
        BuildThreadSummaries();
        _loadingOlder = false;
    }

    private async Task OpenThreadAsync(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (_threadRootMessage is null || _selectedChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task HandleReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (existing is not null)
        {
            existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Models.Reaction(args.Emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        _threadReplyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _threadReplyCounts[rootId] = _threadReplyCounts.GetValueOrDefault(rootId) + 1;
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        _threadReplyCounts.GetValueOrDefault(messageId);

    private void UpdateChannelUnreadCount(int channelId)
    {
        var index = _channels.FindIndex(c => c.Id == channelId);
        if (index >= 0)
        {
            var ch = _channels[index];
            _channels[index] = ch with { UnreadCount = 0 };
        }
    }
}

.chat-container {
    display: flex;
    height: 100%;
    width: 100%;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
}

/* Sidebar */
.panel-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

/* Main message area */
.panel-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.panel-main--full {
    /* When no thread is open, the main area takes remaining space */
}

/* Thread panel */
.panel-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

/* Main header */
.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.main-header h2 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #1a1a1a;
}

.main-header-desc {
    font-size: 13px;
    color: #777;
    margin-top: 2px;
    display: block;
}

/* Message list */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
}

/* States */
.loading-indicator {
    text-align: center;
    color: #999;
    font-size: 13px;
    padding: 12px;
}

.loading-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 16px;
}

.empty-state {
    text-align: center;
    color: #999;
    font-size: 15px;
    padding: 48px 24px;
}

@page "/chat"
@layout sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Layout.ChatLayout
@namespace sv_7398c9d0b0a7421d8c96cdfe6da4f173.Components.Pages.Chat
@rendermode InteractiveServer
@inject Services.IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <!-- Left sidebar: Channel list -->
    <div class="panel-sidebar">
        <ChannelList Channels="_channels"
                     SelectedChannelId="_selectedChannelId"
                     OnChannelSelected="SelectChannelAsync" />
    </div>

    <!-- Main message area -->
    <div class="panel-main @(_threadRootMessage is null ? "panel-main--full" : "")">
        @if (_selectedChannel is not null)
        {
            <div class="main-header">
                <h2># @_selectedChannel.Name</h2>
                <span class="main-header-desc">@_selectedChannel.Description</span>
            </div>

            <div class="message-list" @onscroll="HandleScroll" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in _messages)
                {
                    <MessageBubble Message="msg"
                                   ThreadReplyCount="GetThreadReplyCount(msg.Id)"
                                   OnOpenThread="OpenThreadAsync"
                                   OnReact="HandleReactionAsync" />
                }
                @if (_messages.Count == 0 && !_loading)
                {
                    <div class="empty-state">No messages yet. Start the conversation!</div>
                }
            </div>

            <MessageInput Placeholder="@($"Message #{_selectedChannel.Name}")"
                          ButtonText="Send"
                          OnSubmit="SendMessageAsync" />
        }
        else if (_loading)
        {
            <div class="loading-state">Loading…</div>
        }
    </div>

    <!-- Right panel: Thread view -->
    @if (_threadRootMessage is not null)
    {
        <div class="panel-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnReply="SendThreadReplyAsync" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Models.Channel> _channels = [];
    private List<Models.Message> _messages = [];
    private List<Models.Message> _threadReplies = [];
    private Dictionary<int, int> _threadReplyCounts = new();

    private Models.Channel? _selectedChannel;
    private int? _selectedChannelId;
    private Models.Message? _threadRootMessage;

    private bool _loading;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0].Id);
        }

        _loading = false;
    }

    private async Task SelectChannelAsync(int channelId)
    {
        if (_selectedChannelId == channelId) return;

        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = [];
        _threadReplyCounts = new();
        _threadRootMessage = null;
        _threadReplies = [];
        _allOlderLoaded = false;

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channelId);
        UpdateChannelUnreadCount(channelId);
    }

    private async Task SendMessageAsync(string content)
    {
        if (_selectedChannelId is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannelId.Value, content, null);
        _messages.Add(msg);
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production.
        // Here we provide a manual trigger via the loading state.
        // The @onscroll fires on every scroll; we check position in a real app.
        // For this implementation, we load older messages when near the top.
        if (_loadingOlder || _allOlderLoaded || _selectedChannelId is null) return;

        // In a production app, you'd check scrollTop via JS interop.
        // Simplified: this method is called on scroll, we load if we haven't yet loaded all.
        await LoadOlderMessagesAsync();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _selectedChannelId is null) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_selectedChannelId.Value, _messages.Count, PageSize);

        if (older.Count < PageSize)
        {
            _allOlderLoaded = true;
        }

        _messages.InsertRange(0, older);
        BuildThreadSummaries();
        _loadingOlder = false;
    }

    private async Task OpenThreadAsync(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(messageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReplyAsync(string content)
    {
        if (_threadRootMessage is null || _selectedChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannelId.Value, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] =
            _threadReplyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task HandleReactionAsync((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
        if (existing is not null)
        {
            existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Models.Reaction(args.Emoji, ["You"]));
        }
    }

    private void BuildThreadSummaries()
    {
        _threadReplyCounts.Clear();
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _threadReplyCounts[rootId] = _threadReplyCounts.GetValueOrDefault(rootId) + 1;
        }
    }

    private int GetThreadReplyCount(int messageId) =>
        _threadReplyCounts.GetValueOrDefault(messageId);

    private void UpdateChannelUnreadCount(int channelId)
    {
        var index = _channels.FindIndex(c => c.Id == channelId);
        if (index >= 0)
        {
            var ch = _channels[index];
            _channels[index] = ch with { UnreadCount = 0 };
        }
    }
}

