toolArgs.file_text:
.chat-container {
    display: flex;
    height: 100%;
    width: 100%;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
}

/* Sidebar */
.panel-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

/* Main message area */
.panel-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.panel-main--full {
    /* When no thread is open, the main area takes remaining space */
}

/* Thread panel */
.panel-thread {
    width: 25%;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

/* Main header */
.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
}

.main-header h2 {
    margin: 0;
    font-size: 18px;
    font-weight: 700;
    color: #1a1a1a;
}

.main-header-desc {
    font-size: 13px;
    color: #777;
    margin-top: 2px;
    display: block;
}

/* Message list */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 0;
}

/* States */
.loading-indicator {
    text-align: center;
    color: #999;
    font-size: 13px;
    padding: 12px;
}

.loading-state {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 16px;
}

.empty-state {
    text-align: center;
    color: #999;
    font-size: 15px;
    padding: 48px 24px;
}

